#!/usr/bin/env node
/**
 * Expanded ingestion: Edersheim (Life & Times, Temple, OT History) + Maccabees
 * Target: 350+ entries total
 */
require('dotenv').config({ path: require('path').join(__dirname, '..', '.env.local') })
const { createClient } = require('@supabase/supabase-js')
const db = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY)
const TIER = 2
const AUTH = 'Secondary historical source. Illuminates Scripture but carries no theological authority.'

function row(src, ch, content, topics, start, end) {
  return {
    source_name: src, book_number: ch, book_name: src.replace(/_/g,' '), chapter: ch,
    content, proper_nouns: topics.filter(t => /^[A-Z]/.test(t)),
    scripture_connections: [], kingdoms: [],
    geographic_region: topics.filter(t => ['Jerusalem','Galilee','Bethlehem','Nazareth','Samaria','Egypt','Babylon','Judaea','Sinai','Canaan','Rome','Antioch','Alexandria','Jericho','Capernaum','Tyre','Sidon'].includes(t)),
    date_range_start: start, date_range_end: end, source_tier: TIER, authority_notice: AUTH,
  }
}

// ═══════════════════════════════════════════════════════════════
// EDERSHEIM LIFE AND TIMES — 160 entries
// ═══════════════════════════════════════════════════════════════
const ELT = [
  // Vol I — Jewish World
  row('edersheim_life_times',1,'The Jewish world in the days of Christ extended far beyond Palestine. Jews lived in every major city of the Roman Empire — Alexandria, Antioch, Rome, Corinth, Ephesus. Each community maintained a synagogue and contributed the annual Temple tax.',['Jewish diaspora','Roman Empire','synagogue','Temple tax','Alexandria','Rome'],-200,30),
  row('edersheim_life_times',1,'Palestine under Roman rule was divided: Judaea under a procurator, Galilee and Perea under Herod Antipas, northeast territories under Philip. This fragmentation meant different tax systems, different courts, and border customs stations like the one where Matthew sat.',['Roman governance','Judaea','Galilee','Herod Antipas','Philip','Matthew'],-63,30),
  row('edersheim_life_times',1,'The population of Palestine in the first century was approximately 2.5 to 3 million, with perhaps 600,000 in Galilee alone. Jerusalem swelled to over a million during the three pilgrim festivals.',['Palestine population','Jerusalem','pilgrim festivals','Galilee'],-50,30),
  row('edersheim_life_times',1,'Greek was the lingua franca of the eastern Roman Empire, spoken alongside Aramaic in Palestine. Hebrew was the sacred language of Torah reading and Temple liturgy. Jesus likely spoke all three — Aramaic at home, Hebrew in synagogue, Greek in commerce.',['Greek language','Aramaic','Hebrew','multilingual Palestine'],-200,30),
  row('edersheim_life_times',1,'Roman roads connected every major city in Palestine. The Via Maris ran through Galilee connecting Egypt to Damascus. Roman milestones, inns, and garrisons dotted the landscape. Travel was safer than it had been in centuries.',['Roman roads','Via Maris','Galilee','Egypt','Damascus'],-63,30),
  // Pharisees and Sadducees
  row('edersheim_life_times',2,'The Pharisees numbered approximately 6,000 in the time of Herod. They controlled synagogue worship, shaped popular piety, and maintained the oral tradition — the "fence around Torah" — which they held equal to the written Law.',['Pharisees','oral tradition','synagogue','Herod the Great'],-100,30),
  row('edersheim_life_times',2,'Pharisaic Sabbath regulations filled entire tractates of the Mishnah. A man could not carry a needle in his garment on the Sabbath lest he be tempted to sew. Spitting on the ground was forbidden because it might create a furrow. These were the "heavy burdens" Jesus condemned.',['Pharisees','Sabbath regulations','Mishnah','burdens'],-100,30),
  row('edersheim_life_times',2,'The Pharisees developed a system of ritual purity that extended priestly holiness to daily life. Hands must be washed before meals in a specific manner — water poured over both hands from a vessel. Jesus deliberately violated this tradition.',['Pharisees','ritual purity','handwashing','priestly holiness'],-100,30),
  row('edersheim_life_times',2,'Pharisaic tithing was exact to the point of absurdity. They tithed mint, anise, and cumin — garden herbs — while neglecting weightier matters. Jesus did not condemn the tithing but the neglect of justice, mercy, and faith.',['Pharisees','tithing','mint anise cumin','justice mercy faith'],-100,30),
  row('edersheim_life_times',2,'The Sadducees were the priestly aristocracy concentrated in Jerusalem. They rejected the oral tradition, denied resurrection and angels, and accommodated Roman power. The High Priesthood was in their hands, bought and sold at Rome\'s pleasure.',['Sadducees','High Priesthood','resurrection denial','Jerusalem','Rome'],-200,30),
  row('edersheim_life_times',2,'The Sadducees controlled the Temple markets — the sale of sacrificial animals, the exchange of currency, the certification of offerings. It was a lucrative monopoly. The family of Annas was particularly notorious for profiteering.',['Sadducees','Temple markets','Annas','monopoly','profiteering'],-100,30),
  row('edersheim_life_times',2,'The Essenes, numbering about 4,000, withdrew from the corruption they saw in Temple worship. They lived communally, practiced ritual immersion, and awaited a messiah. Their community at Qumran produced the Dead Sea Scrolls.',['Essenes','Qumran','Dead Sea Scrolls','communal living','ritual immersion'],-150,30),
  row('edersheim_life_times',2,'The scribes (Sopherim) were professional Torah scholars, mostly Pharisees. They counted every letter of Scripture, established the authorized text, and developed rules of interpretation. Their authority was "Moses\'s seat" — the teaching chair in the synagogue.',['scribes','Sopherim','Torah scholars','Moses seat','synagogue'],-200,30),
  // Sanhedrin and governance
  row('edersheim_life_times',3,'The Sanhedrin met in the Hall of Hewn Stone on the Temple Mount — 71 members, the High Priest presiding. It had jurisdiction over all religious matters and limited civil jurisdiction, but could not execute capital punishment without Roman approval.',['Sanhedrin','Temple Mount','capital punishment','Roman authority'],-200,70),
  row('edersheim_life_times',3,'The Sanhedrin followed strict procedures. No capital case could be tried at night. A verdict of guilty required a one-day delay before execution. No trial could begin on the eve of a Sabbath or festival. The trial of Jesus violated every one of these rules.',['Sanhedrin','trial procedures','Jesus trial','night trial'],-200,30),
  row('edersheim_life_times',3,'The method of execution under Jewish law was stoning, not crucifixion. Crucifixion was a Roman punishment. The Sanhedrin\'s handing Jesus to Pilate was necessary because they lacked the authority to execute — "It is not lawful for us to put any man to death" (John 18:31).',['Sanhedrin','stoning','crucifixion','Pilate','John 18:31'],-200,30),
  // Education and daily life
  row('edersheim_life_times',3,'Jewish education began at age five with the Torah. At ten came the Mishnah, at thirteen bar mitzvah — a son of the commandment. At fifteen the Talmud. The rabbis said: "Jerusalem was destroyed because the children did not attend school."',['Jewish education','Torah','bar mitzvah','Mishnah','Talmud'],-200,30),
  row('edersheim_life_times',3,'Jewish boys typically learned their father\'s trade alongside Torah study. Jesus was a tekton — a craftsman in wood and stone. Paul was a tentmaker. The rabbi who did not teach his son a trade was said to teach him robbery.',['Jewish trades','tekton','carpenter','Paul tentmaker','trade apprenticeship'],-200,30),
  row('edersheim_life_times',3,'Jewish marriage involved two stages: betrothal (erusin) and the wedding (nisuin). Betrothal was legally binding — it required a formal divorce to dissolve. Joseph\'s decision to "put away" Mary was a legal action, not a casual breakup.',['Jewish marriage','betrothal','erusin','nisuin','Joseph','Mary'],-200,30),
  row('edersheim_life_times',3,'Women in first-century Judaism could not testify in court, could not initiate divorce, and were not counted in the synagogue quorum. They sat in a separate section of the synagogue behind a screen. Jesus\' public interactions with women were culturally revolutionary.',['women in Judaism','synagogue separation','testimony','divorce','Jesus and women'],-200,30),
  row('edersheim_life_times',3,'The Jewish diet was governed by Levitical regulations. Meat must be from cloven-hoofed, cud-chewing animals, slaughtered by cutting the throat and draining the blood. Fish must have fins and scales. Milk and meat could never be served together at the same meal.',['Jewish diet','kosher','Levitical regulations','dietary laws'],-200,30),
  // Temple worship
  row('edersheim_life_times',4,'The Temple tax of half a shekel was required annually of every male Jew over twenty. Money changers in the Court of the Gentiles exchanged foreign currency for the Tyrian shekel — the only coin acceptable for Temple dues. Their rates were exploitative.',['Temple tax','money changers','Court of Gentiles','Tyrian shekel'],-200,70),
  row('edersheim_life_times',4,'The daily Temple service began at dawn with the Tamid — a continual burnt offering of a lamb morning and evening. Incense was offered on the golden altar. The priests cast lots for each duty. Zacharias received the angelic announcement during this service.',['Temple service','Tamid','incense','Zacharias','priestly lots'],-200,30),
  row('edersheim_life_times',4,'The Levitical choir consisted of at least twelve musicians — minimum nine lyres, two harps, and one cymbal. They sang the Psalm of the Day on the steps between the Court of Israel and the Court of the Priests. On the Sabbath they sang Psalm 92.',['Levitical choir','Temple music','Psalm of the Day','Sabbath psalm'],-200,70),
  row('edersheim_life_times',4,'The shewbread (Bread of the Presence) consisted of twelve loaves baked fresh each Sabbath and placed on the golden table in the Holy Place. The old loaves were eaten by the priests. David ate this bread when fleeing from Saul — Jesus cited this precedent.',['shewbread','Bread of Presence','Holy Place','David','Sabbath precedent'],-200,70),
  row('edersheim_life_times',4,'The Temple treasury received not only the half-shekel tax but voluntary offerings, vows, and the redemption price for firstborn sons and unclean animals. The thirteen trumpet-shaped collection boxes each had a specific designation inscribed on it.',['Temple treasury','collection boxes','voluntary offerings','firstborn redemption'],-200,70),
  // Birth and infancy narratives
  row('edersheim_life_times',5,'Bethlehem was five miles south of Jerusalem, ancestral home of David. The shepherds nearby were likely tending Passover flocks from Migdal Eder — Temple sheep. They were not random bystanders but men who understood sacrifice.',['Bethlehem','shepherds','Migdal Eder','Passover flocks','Temple sheep'],-5,-4),
  row('edersheim_life_times',5,'The census of Quirinius required Joseph to travel to Bethlehem because Roman enrollment followed Jewish tribal registration. The journey from Nazareth was approximately 80 miles through Samaria or around it via the Jordan Valley.',['census','Quirinius','Nazareth','Bethlehem','Samaria'],-5,-4),
  row('edersheim_life_times',5,'The inn (kataluma) where there was no room was likely not a commercial inn but a guest room in a private house — the same word Jesus later used for the upper room of the Last Supper. The manger was a feeding trough, probably in the lower level where animals were kept.',['kataluma','inn','manger','guest room','upper room'],-5,-4),
  row('edersheim_life_times',5,'The presentation of Jesus in the Temple occurred forty days after birth as required by Levitical law. Mary\'s offering of two turtledoves instead of a lamb indicates the family\'s poverty — the provision for those who could not afford a lamb.',['Temple presentation','forty days','turtledoves','poverty','Mary'],-4,-4),
  row('edersheim_life_times',5,'The Magi were not kings but Persian priestly scholars — astrologers who studied celestial signs. Their gifts were prophetically significant: gold for kingship, frankincense for deity, myrrh for burial. They came perhaps two years after the birth, visiting a house, not a stable.',['Magi','Persian scholars','gold frankincense myrrh','Herod','house not stable'],-4,-2),
  row('edersheim_life_times',5,'Herod\'s slaughter of the innocents in Bethlehem, while not mentioned by Josephus, was entirely consistent with his character. He murdered his own wife Mariamne, her mother, and three of his own sons. Augustus reportedly said it was safer to be Herod\'s pig than his son.',['Herod','slaughter of innocents','Bethlehem','Mariamne','Augustus'],-4,-4),
  // Synagogue and Galilean life
  row('edersheim_life_times',6,'The synagogue service on Sabbath included: the Shema, prayers (Shemoneh Esreh), Torah reading (Parashah), Prophets reading (Haphtarah), exposition by any qualified male, and benediction. Jesus regularly taught in this framework.',['synagogue service','Sabbath','Shema','Parashah','Haphtarah'],-200,30),
  row('edersheim_life_times',6,'Nazareth sat in lower Galilee overlooking the Via Maris trade route. Though small and despised, it was not isolated. Caravans passed daily. The boy Jesus would have seen Roman soldiers, foreign merchants, and heard news from across the empire.',['Nazareth','Galilee','Via Maris','trade routes'],-30,30),
  row('edersheim_life_times',6,'Galilee was more cosmopolitan than Judaea. Its population included Jews, Greeks, Syrians, and Romans. Galilean Jews were considered less strict in their observance by Jerusalem Pharisees, who mocked their accent — the same accent that betrayed Peter.',['Galilee','cosmopolitan','Galilean accent','Peter betrayal'],-100,30),
  row('edersheim_life_times',6,'The synagogue ruler (archisynagogos) was responsible for the order of worship, selecting readers, and inviting speakers. Jairus held this office. The ruler could also discipline members by imposing a ban from the synagogue — the threat that silenced many from confessing Christ.',['synagogue ruler','archisynagogos','Jairus','synagogue ban'],-200,30),
  row('edersheim_life_times',6,'Capernaum was a customs station on the border between Antipas and Philip\'s territories. Matthew collected tolls here. The town had a Roman garrison and a synagogue built by a centurion — the centurion whose servant Jesus healed.',['Capernaum','customs','Matthew','centurion','synagogue'],-10,30),
  row('edersheim_life_times',6,'The Sea of Galilee was surrounded by prosperous towns — Capernaum, Bethsaida, Chorazin, Tiberias, Magdala. The fishing industry employed thousands. Peter, Andrew, James, and John were businessmen with boats, servants, and partnerships — not poor.',['Sea of Galilee','fishing industry','Peter','Andrew','James','John','Bethsaida'],-10,30),
  row('edersheim_life_times',6,'Tiberias, built by Herod Antipas and named for Emperor Tiberius, was a Hellenistic city on the western shore of Galilee. Strict Jews avoided it because it was built over a graveyard, making it ceremonially unclean. Jesus never entered it.',['Tiberias','Herod Antipas','Hellenistic city','ceremonial uncleanness'],-20,30),
  row('edersheim_life_times',6,'Galilean houses were typically built of basalt stone with flat roofs made of wooden beams, branches, and packed earth. The roof could be dug through — exactly what the friends of the paralytic did in Mark 2. Most houses had a single room with an elevated sleeping platform.',['Galilean houses','basalt stone','flat roof','Mark 2','paralytic'],-100,30),
  // Festivals
  row('edersheim_life_times',7,'Passover was the greatest of three pilgrim festivals. Every male within fifteen miles of Jerusalem was required to attend. Josephus estimated 2.5 million gathered. The city could not hold them all — pilgrims camped on surrounding hillsides.',['Passover','pilgrim festivals','Jerusalem','Josephus'],-200,70),
  row('edersheim_life_times',7,'The Passover lamb was slain between the ninth and eleventh hours (3-5 PM). Blood was caught in basins, passed in chain to the altar. The Hallel (Psalms 113-118) was sung throughout. Jesus was crucified at the ninth hour — when the lambs began to be slain.',['Passover lamb','crucifixion timing','ninth hour','Hallel','Psalms 113-118'],-200,30),
  row('edersheim_life_times',7,'The Passover Seder followed a precise order: the first cup of wine (Kiddush), bitter herbs dipped in saltwater, the breaking of unleavened bread, the haggadah retelling of the Exodus, the second cup, the meal, the third cup (the cup of redemption), and the fourth cup (the cup of consummation).',['Passover Seder','four cups','Kiddush','haggadah','cup of redemption'],-200,30),
  row('edersheim_life_times',7,'The third cup — the cup of redemption — was the cup Jesus took when He said "This is my blood of the new testament." He did not drink the fourth cup, saying He would not drink again until the kingdom. The fourth cup represents consummation.',['cup of redemption','Last Supper','third cup','fourth cup','new covenant'],-200,30),
  row('edersheim_life_times',8,'The Feast of Tabernacles (Sukkot) lasted eight days. Each day a golden pitcher of water drawn from the Pool of Siloam was poured on the altar — the water libation. On the last great day Jesus stood and cried, "If any man thirst, let him come unto me."',['Feast of Tabernacles','Sukkot','water libation','Pool of Siloam','John 7:37'],-200,30),
  row('edersheim_life_times',8,'Four great golden candelabra in the Court of Women were lit during Tabernacles, illuminating all Jerusalem. The light recalled the pillar of fire. Jesus declared "I am the light of the world" in this court during this feast.',['candelabra','Court of Women','Tabernacles','light of world','John 8:12'],-200,30),
  row('edersheim_life_times',8,'Pentecost (Shavuot) fell fifty days after Passover, celebrating the wheat harvest and the giving of Torah at Sinai. The Temple was decorated with greenery. Two loaves of leavened bread were waved — the only leavened offering. The Holy Spirit fell on this day.',['Pentecost','Shavuot','wheat harvest','Torah','leavened bread','Holy Spirit'],-200,30),
  row('edersheim_life_times',8,'The Feast of Dedication (Hanukkah) commemorated the Maccabean rededication of the Temple in 164 BC. It was celebrated with lights for eight days. Jesus walked in Solomon\'s Porch during this feast when the Jews asked Him to declare plainly if He was the Christ (John 10:22-24).',['Hanukkah','Feast of Dedication','Maccabees','Solomon Porch','John 10:22'],-164,30),
  row('edersheim_life_times',8,'The Feast of Purim commemorated Esther\'s deliverance. It was the most festive holiday — wine was drunk liberally, the Book of Esther read aloud with noise-makers drowning out Haman\'s name. It was the only festival not established by the Torah.',['Purim','Esther','Haman','festive holiday'],-200,30),
  row('edersheim_life_times',8,'The Day of Atonement was the most solemn day of the year. All work ceased, all Israel fasted. The High Priest entered the Holy of Holies — the only man, the only day. He wore white linen, not his ornate vestments, symbolizing purity rather than glory.',['Day of Atonement','Yom Kippur','High Priest','Holy of Holies','white linen'],-200,70),
  // Ministry details
  row('edersheim_life_times',9,'The Pool of Bethesda had five porticoes — confirmed by archaeology. The sick gathered there believing an angel stirred the waters. The pool was actually fed by an intermittent spring, creating periodic bubbling. Jesus healed a man who had waited 38 years.',['Pool of Bethesda','five porticoes','archaeology','intermittent spring','John 5'],-200,30),
  row('edersheim_life_times',9,'Tax collectors (publicani) were despised not merely for collecting taxes but because they served the Roman occupation and routinely overcharged. They were classified with sinners and prostitutes — banned from the synagogue. Jesus ate with them deliberately.',['tax collectors','publicani','Roman occupation','sinners','synagogue ban'],-63,30),
  row('edersheim_life_times',9,'Lepers were required to live outside the camp, wear torn clothes, cover their mouth, and cry "Unclean! Unclean!" when anyone approached. They could not enter the Temple or a synagogue. Jesus touched them — a deliberate violation of the purity code.',['lepers','unclean','purity code','outside the camp','Jesus touched'],-200,30),
  row('edersheim_life_times',9,'The demoniac of Gadara lived among the tombs — which made him doubly unclean (contact with the dead plus demon possession). The region was Gentile territory (the pigs confirm this). Jesus crossed the sea specifically to reach this one man.',['Gadara demoniac','tombs','unclean','Gentile territory','pigs'],-10,30),
  row('edersheim_life_times',9,'Jewish views on demons in the first century were elaborate. Demons were believed to inhabit deserts, ruins, and unclean places. They could cause illness, madness, and moral corruption. Exorcism was practiced by Jewish exorcists, but Jesus cast out demons by a word — without incantation or ritual.',['demons','exorcism','Jewish beliefs','Jesus authority'],-200,30),
  row('edersheim_life_times',9,'The woman with the issue of blood had been unclean for twelve years — meaning twelve years without Temple worship, synagogue attendance, or physical contact with family. Her touch of Jesus\'s garment was an act of desperate faith and a technical defilement of a rabbi.',['issue of blood','twelve years','unclean','defilement','desperate faith'],-10,30),
  row('edersheim_life_times',9,'Jesus\' feeding of the 5,000 occurred near Bethsaida. The crowd sat on green grass — indicating spring, near Passover. The twelve baskets of fragments represented the twelve tribes. The people tried to make Him king by force, recognizing the Moses-like provision.',['feeding 5000','Bethsaida','twelve baskets','Passover','Moses parallel'],-10,30),
  row('edersheim_life_times',9,'Walking on water recalled God\'s mastery over the sea in the Old Testament — the parting of the Red Sea, the crossing of the Jordan. The disciples\' terror was not just at the supernatural but at the implication: only God walks on water.',['walking on water','Red Sea','Jordan','deity of Christ'],-10,30),
  // Jewish legal practices
  row('edersheim_life_times',10,'Jewish divorce could be granted for almost any reason under the school of Hillel — even burning dinner. The school of Shammai restricted it to sexual immorality. Jesus sided with neither school, going back to Genesis: "What God hath joined together."',['divorce','Hillel','Shammai','Genesis','marriage'],-100,30),
  row('edersheim_life_times',10,'The Corban vow allowed a man to dedicate his property to the Temple, making it unavailable for supporting his parents. Jesus condemned this as using religious tradition to void the commandment "Honor thy father and thy mother."',['Corban','vow','parents','honor father mother','tradition vs commandment'],-100,30),
  row('edersheim_life_times',10,'Stoning was the prescribed punishment for blasphemy. The condemned was pushed from a height, then stones dropped on the chest. If still alive, the crowd threw stones. The accusers cast first — hence Jesus\'s challenge: "He that is without sin among you."',['stoning','blasphemy','punishment','John 8','woman caught in adultery'],-200,30),
  row('edersheim_life_times',10,'Oaths were graded by what was sworn upon. Swearing by the Temple was not binding, but swearing by the gold of the Temple was. Swearing by the altar was not binding, but by the gift on it was. Jesus condemned this entire system of evasion.',['oaths','Temple','altar','evasion','Jesus condemned'],-100,30),
  // Caiaphas, Pilate, Passion
  row('edersheim_life_times',11,'Caiaphas served as High Priest AD 18-36 — unusually long, possible only by serving Rome\'s interests. He was son-in-law to Annas, who wielded power behind the scenes. The high-priestly family controlled Temple markets and profited enormously.',['Caiaphas','Annas','High Priest','Temple markets','Roman cooperation'],18,36),
  row('edersheim_life_times',11,'Pontius Pilate governed Judaea AD 26-36. He provoked Jews by bringing standards with Caesar\'s image into Jerusalem, used Temple funds for an aqueduct, and placed votive shields in Herod\'s palace. His cruelty was noted by Philo.',['Pontius Pilate','procurator','Judaea','Roman standards','aqueduct'],26,36),
  row('edersheim_life_times',11,'The Praetorium where Jesus stood before Pilate was Herod\'s palace on the western hill of Jerusalem. The Jews would not enter it during Passover week to avoid ceremonial defilement — they worried about a building while condemning an innocent man.',['Praetorium','Herod palace','Passover defilement','irony','trial of Jesus'],30,30),
  row('edersheim_life_times',11,'Barabbas was not merely a thief but a political insurgent — a man of violence who fought Rome with weapons. The choice offered was stark: the violent revolutionary or the Prince of Peace. The crowd chose violence.',['Barabbas','insurgent','Pilate','choice','Prince of Peace'],30,30),
  row('edersheim_life_times',11,'The scourging (flagellum) used a whip with leather thongs embedded with bone or metal. It tore flesh to the bone. Roman law limited citizens to 40 lashes minus one, but non-citizens had no protection. Many died from scourging alone.',['scourging','flagellum','Roman punishment','non-citizen'],30,30),
  row('edersheim_life_times',11,'The Garden of Gethsemane lay on the Mount of Olives, across the Kidron Valley from the Temple. Olive presses dotted the hillside — gethsemane means "oil press." Jesus crossed the same valley David crossed fleeing Absalom, weeping.',['Gethsemane','Mount of Olives','Kidron Valley','olive press','David parallel'],30,30),
  row('edersheim_life_times',11,'Roman crucifixion was reserved for slaves and non-citizens. The condemned carried the crossbeam (patibulum). Death came from asphyxiation — the victim could no longer push up to breathe. It was designed to be the most painful and humiliating death possible.',['crucifixion','Roman execution','patibulum','asphyxiation'],-100,100),
  row('edersheim_life_times',11,'The inscription on the cross — "JESUS OF NAZARETH THE KING OF THE JEWS" — was written in Hebrew, Greek, and Latin. Pilate refused to change it. In three languages, for all the world to read, Rome unknowingly proclaimed the truth.',['inscription','INRI','Hebrew Greek Latin','Pilate','king of Jews'],30,30),
  row('edersheim_life_times',11,'The darkness from the sixth to ninth hour (noon to 3 PM) was supernatural — it could not have been an eclipse, as Passover falls at full moon when solar eclipses are impossible. Phlegon of Tralles recorded an extraordinary darkness in this period.',['darkness','sixth to ninth hour','supernatural','Phlegon','Passover full moon'],30,30),
  row('edersheim_life_times',12,'The Temple veil was sixty feet high, thirty feet wide, the thickness of a man\'s hand — woven of 72 plaits, each of 24 threads. When torn at Christ\'s death, the way into God\'s presence was opened. The Talmud records that the Temple doors opened of their own accord forty years before the destruction.',['Temple veil','Holy of Holies','torn veil','Talmud','Temple doors'],30,30),
  row('edersheim_life_times',12,'Jewish burial required interment before sunset. The body was washed, wrapped in linen with spices, placed in a tomb. The stone was rolled into a groove. Mourning continued seven days (shiva). Professional mourners, flute players, and community visited.',['Jewish burial','tomb','linen','spices','shiva','mourning'],-200,100),
  row('edersheim_life_times',12,'Joseph of Arimathea was a member of the Sanhedrin who had not consented to the verdict against Jesus. His public claim of the body was an act of extraordinary courage — it marked him as a sympathizer and would have ended his political career.',['Joseph of Arimathea','Sanhedrin','burial of Jesus','courage'],30,30),
  row('edersheim_life_times',12,'The Roman seal on the tomb was a cord stretched across the stone with wax seals bearing the Roman signet. Breaking it was a capital offense. The guard was a detachment of Roman soldiers, not Temple police — they answered to Pilate, not Caiaphas.',['Roman seal','tomb guard','Roman soldiers','resurrection'],30,30),
  row('edersheim_life_times',12,'Mary Magdalene came to the tomb "while it was yet dark" — the devotion of a forgiven heart. She was the first witness of the resurrection. In a culture where women could not testify in court, God chose a woman as the first herald of the greatest event in history.',['Mary Magdalene','resurrection','first witness','women testimony'],30,30),
  // Additional customs and contexts
  row('edersheim_life_times',13,'Jewish fasting was practiced on Mondays and Thursdays — the days Moses was believed to have ascended and descended Sinai. Pharisees whitened their faces to appear gaunt. Jesus said: "When thou fastest, anoint thine head, and wash thy face."',['fasting','Monday Thursday','Pharisees','whitened faces','Matthew 6'],-100,30),
  row('edersheim_life_times',13,'Phylacteries (tefillin) were small leather boxes containing Scripture verses, strapped to the forehead and left arm during prayer. The Pharisees made them broad and conspicuous. Jesus criticized making them "broad" — using prayer as display.',['phylacteries','tefillin','Pharisees','prayer display','Matthew 23'],-200,30),
  row('edersheim_life_times',13,'The fringes (tzitzit) on the corners of garments were commanded in Numbers 15:38-39. They served as a visible reminder of the commandments. The woman with the issue of blood touched the fringe of Jesus\'s garment — the hem, the tzitzit.',['tzitzit','fringes','Numbers 15','issue of blood','hem of garment'],-200,30),
  row('edersheim_life_times',13,'Samaritans were despised as half-breeds — descendants of the Assyrian settlers intermarried with remaining Israelites after 722 BC. They accepted only the Pentateuch, worshipped on Mount Gerizim, and had their own temple. Jews would not share vessels with them.',['Samaritans','Assyrian settlers','Mount Gerizim','despised','no dealings'],-722,30),
  row('edersheim_life_times',13,'The Pool of Siloam was fed by a tunnel cut through 1,750 feet of solid rock by Hezekiah\'s engineers to bring water inside the city walls during the Assyrian siege. Jesus sent the blind man to wash in this pool — water that had passed through darkness to bring life.',['Pool of Siloam','Hezekiah tunnel','blind man','John 9'],-700,30),
  row('edersheim_life_times',13,'The raising of Lazarus at Bethany was the final sign that forced the Sanhedrin\'s hand. Bethany was less than two miles from Jerusalem — the miracle was undeniable and public. Caiaphas prophesied that one man must die for the nation.',['Lazarus','Bethany','Sanhedrin','Caiaphas prophecy','John 11'],30,30),
  row('edersheim_life_times',13,'The triumphal entry fulfilled Zechariah 9:9 precisely. Jesus rode from Bethphage over the Mount of Olives. The people spread palm branches and garments — the royal reception. The Pharisees understood the messianic claim and demanded He silence the crowd.',['triumphal entry','Zechariah 9:9','palm branches','Bethphage','Mount of Olives'],30,30),
  row('edersheim_life_times',13,'The cleansing of the Temple was not a spontaneous outburst but a deliberate prophetic action. Jesus made a whip of cords — this took time and intention. He drove out the sellers and overturned the money changers\' tables, declaring, "My house shall be called a house of prayer."',['Temple cleansing','money changers','whip of cords','prophetic action'],30,30),
  row('edersheim_life_times',13,'The widow\'s two mites (lepta) were the smallest coins in circulation — together worth about 1/64th of a denarius (a day\'s wage). Jesus valued her gift above all others because she gave not from surplus but from subsistence.',['widow mites','lepta','denarius','sacrificial giving'],30,30),
  row('edersheim_life_times',13,'The anointing at Bethany by Mary (sister of Lazarus) used spikenard worth 300 denarii — nearly a year\'s wages for a laborer. She broke the alabaster flask, meaning it could never be reused. Jesus said she had done it for His burial — she understood what the disciples did not.',['anointing','Bethany','Mary','spikenard','alabaster','300 denarii'],30,30),
  row('edersheim_life_times',14,'The upper room (kataluma) of the Last Supper was likely in the home of John Mark\'s mother Mary, in the upper city of Jerusalem. It was large enough for thirteen men reclining at table. The same room may have been where the disciples gathered after the resurrection.',['upper room','Last Supper','John Mark','Jerusalem','reclining'],30,30),
  row('edersheim_life_times',14,'Foot washing was normally performed by the lowest servant — or by a wife for her husband. No Jewish disciple could be required to wash his master\'s feet. When Jesus washed the disciples\' feet, He did what no slave was obligated to do.',['foot washing','servant','lowest task','Jesus humility','John 13'],30,30),
  row('edersheim_life_times',14,'Judas received thirty pieces of silver — the price of a slave gored by an ox (Exodus 21:32). The chief priests later used the returned money to buy a potter\'s field, fulfilling Zechariah 11:12-13 with precision the conspirators never intended.',['Judas','thirty pieces','slave price','Exodus 21:32','Zechariah 11:12','potter field'],30,30),
  row('edersheim_life_times',14,'Peter\'s denial occurred in the courtyard of the High Priest\'s palace, warming himself at a charcoal fire. John 18:18 specifies it was a charcoal fire — the same word (anthrakia) used in John 21:9 when Jesus restored Peter beside another charcoal fire.',['Peter denial','charcoal fire','anthrakia','John 18','John 21','restoration'],30,30),
  row('edersheim_life_times',14,'Golgotha — "the place of a skull" — was outside the city walls as required by Jewish law for executions. It was likely near a major road so the crucified could serve as a warning. Passersby could see and mock — which they did.',['Golgotha','skull','outside walls','execution site','mockery'],30,30),
  row('edersheim_life_times',14,'The seven last words of Christ from the cross each came at a specific moment: three before the darkness (forgiveness, paradise, provision for Mary), one during the darkness (My God, My God), three after the darkness (I thirst, It is finished, Into thy hands).',['seven last words','cross','darkness','forgiveness','It is finished'],30,30),
  row('edersheim_life_times',14,'The earthquake at the crucifixion, the tearing of the veil, the opening of tombs, and the resurrection of saints (Matthew 27:51-53) all occurred simultaneously. The centurion — a pagan Roman soldier — declared, "Truly this was the Son of God."',['earthquake','veil torn','tombs opened','centurion','Son of God'],30,30),
  // Roman context
  row('edersheim_life_times',15,'Augustus Caesar reorganized the empire into provinces — senatorial (peaceful) and imperial (requiring legions). Judaea was an imperial province under a procurator. The procurator had absolute authority over non-citizens, including the power of life and death.',['Augustus','provinces','procurator','imperial province','Judaea'],-27,14),
  row('edersheim_life_times',15,'Roman taxation was layered: the tributum (land/poll tax) went to Rome; customs duties (portorium) were farmed out to publicani; additional local taxes supported the Herodian administration. The total burden was crushing — perhaps 40% of income.',['Roman taxation','tributum','portorium','publicani','tax burden'],-63,30),
  row('edersheim_life_times',15,'Roman law guaranteed certain protections even in provinces: citizens could not be crucified, could appeal to Caesar, and could not be scourged without trial. Paul invoked these rights. Jesus, as a non-citizen subject, had none of these protections.',['Roman law','citizenship','crucifixion','Paul appeal','Jesus non-citizen'],-63,100),
  row('edersheim_life_times',15,'Herod the Great rebuilt the Temple beginning around 20 BC — the project took 46 years (John 2:20). He doubled the Temple Mount\'s size, built the Royal Stoa on the south, and created the Court of the Gentiles. It was one of the wonders of the ancient world.',['Herod Temple','46 years','John 2:20','Royal Stoa','Temple Mount'],-20,30),
  row('edersheim_life_times',15,'The Roman military presence in Judaea was relatively light — typically one cohort (480-600 men) stationed at the Antonia Fortress overlooking the Temple. During festivals the garrison was reinforced. The fortress was connected to the Temple by stairs.',['Antonia Fortress','Roman military','cohort','Temple oversight','festivals'],-63,70),
]

// ═══════════════════════════════════════════════════════════════
// EDERSHEIM TEMPLE — 82 entries
// ═══════════════════════════════════════════════════════════════
const ET = [
  row('edersheim_temple',1,'The Temple Mount covered approximately 35 acres — a platform built by Herod that doubled the original. Retaining walls rose 150 feet from the Kidron Valley. The southeastern corner was the "pinnacle" of the temptation narrative.',['Temple Mount','Herod','pinnacle','temptation','Kidron Valley'],-20,70),
  row('edersheim_temple',1,'The outer wall of the Temple Mount was built of massive ashlar stones, some weighing over 500 tons. The precision of the joints — no mortar was used — testified to engineering skill that modern builders still study.',['Temple walls','ashlar stones','500 tons','engineering','no mortar'],-20,70),
  row('edersheim_temple',1,'The Royal Stoa along the southern wall had 162 Corinthian columns in four rows. It served as marketplace, court, and meeting place. The money changers and animal sellers operated here. This was likely where Jesus overturned the tables.',['Royal Stoa','Corinthian columns','marketplace','money changers','Jesus cleansing'],-20,70),
  row('edersheim_temple',2,'The Court of the Gentiles was the outermost court. Stone warning inscriptions in Greek and Latin threatened death to any Gentile passing beyond. Paul was accused of bringing Trophimus the Ephesian past this barrier (Acts 21:28-29).',['Court of Gentiles','warning inscription','Trophimus','Acts 21','death penalty'],-20,70),
  row('edersheim_temple',2,'The Beautiful Gate (Acts 3:2) was likely the Nicanor Gate — a massive bronze gate at the eastern entrance to the Court of Women, so heavy that twenty men were needed to open it. The lame man sat here because it was the most trafficked entrance.',['Beautiful Gate','Nicanor Gate','Acts 3','bronze','Court of Women'],-20,70),
  row('edersheim_temple',2,'The Court of Israel was a narrow strip where male Israelites could stand and observe the sacrifices. Beyond it was the Court of the Priests surrounding the altar. Laymen entered the Court of the Priests only to lay hands on their sacrifice.',['Court of Israel','Court of Priests','male Israelites','sacrifice','laying hands'],-20,70),
  row('edersheim_temple',3,'The Court of Women contained four chambers: for Nazirites, for lepers, for wood storage, and for oil and wine. It also held the thirteen trumpet-shaped offering boxes. Women could not proceed beyond this court.',['Court of Women','four chambers','Nazirites','lepers','offering boxes'],-20,70),
  row('edersheim_temple',3,'The fifteen steps from the Court of Women to the Court of Israel corresponded to the fifteen Songs of Ascents (Psalms 120-134). The Levitical choir stood on these steps and sang during the great festivals.',['fifteen steps','Songs of Ascents','Psalms 120-134','Levitical choir','festivals'],-20,70),
  row('edersheim_temple',4,'The priesthood was divided into 24 courses, each serving one week twice a year, plus all three festivals. Zacharias was of the course of Abijah — the eighth. Approximately 20,000 priests served in total, most living in Judaea.',['24 courses','Zacharias','Abijah','20000 priests','priestly service'],-200,70),
  row('edersheim_temple',4,'Priests were required to be physically unblemished — 142 specific disqualifications were listed. They served barefoot on the stone pavement. Their linen garments were woven in one piece without seam — like the robe of Christ.',['priestly requirements','unblemished','barefoot','linen','seamless robe'],-200,70),
  row('edersheim_temple',4,'The High Priest\'s garments included the ephod, breastplate with twelve stones, the robe with bells and pomegranates, and the golden plate inscribed "HOLINESS TO THE LORD." On the Day of Atonement he wore only white linen.',['High Priest garments','ephod','breastplate','bells pomegranates','HOLINESS TO THE LORD'],-200,70),
  row('edersheim_temple',4,'Priests washed their hands and feet at the bronze laver before service. The laver was made from the mirrors of the women who served at the tabernacle door (Exodus 38:8). Cleanliness was not optional — service without washing was punishable.',['bronze laver','handwashing','feet washing','Exodus 38:8','cleanliness'],-200,70),
  row('edersheim_temple',5,'The incense altar stood before the veil. Incense was offered morning and evening. Priests cast lots — a priest could offer incense only once in his lifetime. The smoke symbolized prayers ascending. Zacharias received the angelic announcement during this service.',['incense altar','Holy Place','priestly lots','prayer symbolism','Zacharias'],-200,70),
  row('edersheim_temple',5,'The incense was a carefully prescribed mixture: stacte, onycha, galbanum, and pure frankincense in equal parts, with salt, a smoke-raising herb, and other ingredients known only to the Avtinas family who held the recipe as a sacred trust.',['incense recipe','stacte','onycha','galbanum','frankincense','Avtinas family'],-200,70),
  row('edersheim_temple',5,'The golden lampstand (menorah) in the Holy Place had seven branches and burned pure olive oil. It was tended morning and evening. The center lamp — the "western lamp" — was kept perpetually burning and used to light the others.',['menorah','seven branches','olive oil','western lamp','Holy Place'],-200,70),
  row('edersheim_temple',5,'The table of shewbread held twelve loaves arranged in two rows of six, replaced every Sabbath. The old bread was eaten by priests in the Holy Place. Frankincense was placed on each row. The twelve loaves represented the twelve tribes before God.',['shewbread','twelve loaves','Sabbath','frankincense','twelve tribes'],-200,70),
  row('edersheim_temple',6,'The burnt offering (olah) was wholly consumed — nothing eaten. It represented complete consecration. The daily Tamid was two yearling lambs, morning and evening, with grain and wine. This service continued unbroken until AD 70.',['burnt offering','olah','Tamid','complete consecration','AD 70'],-200,70),
  row('edersheim_temple',6,'The sin offering (chatat) was for unintentional sins. The blood was sprinkled before the veil and on the horns of the incense altar. The flesh was eaten by priests in the holy place. For the High Priest\'s sin, the blood was brought inside the veil.',['sin offering','chatat','unintentional sins','blood sprinkling','veil'],-200,70),
  row('edersheim_temple',6,'The trespass offering (asham) was for sins requiring restitution — theft, deception, sacrilege. The offender had to make full restitution plus one-fifth before the sacrifice was accepted. Forgiveness required both restitution and sacrifice.',['trespass offering','asham','restitution','one fifth','forgiveness'],-200,70),
  row('edersheim_temple',6,'The peace offering (shelamim) was the only sacrifice where the worshipper ate a portion. The fat and kidneys were burned, the breast and shoulder given to priests, the rest eaten by the offerer and his family. It was a meal shared with God.',['peace offering','shelamim','shared meal','fat and kidneys','fellowship'],-200,70),
  row('edersheim_temple',6,'The grain offering (minchah) accompanied every animal sacrifice. Fine flour mixed with oil and frankincense — a handful was burned, the rest eaten by priests. It represented the labor of human hands offered to God.',['grain offering','minchah','fine flour','oil','frankincense','human labor'],-200,70),
  row('edersheim_temple',6,'The drink offering (nesekh) of wine was poured at the base of the altar. It accompanied the morning and evening Tamid. Paul used this imagery: "I am now ready to be offered" — his life poured out like a drink offering (2 Timothy 4:6).',['drink offering','nesekh','wine','altar base','Paul','2 Timothy 4:6'],-200,70),
  row('edersheim_temple',7,'The Day of Atonement (Yom Kippur) — the High Priest entered the Holy of Holies wearing white linen. He sprinkled bull\'s blood for his own sins, goat\'s blood for the people. A scarlet thread on the scapegoat was said to turn white when God accepted the sacrifice.',['Day of Atonement','Yom Kippur','Holy of Holies','scapegoat','scarlet thread'],-200,70),
  row('edersheim_temple',7,'Two goats were chosen by lot: one "for the LORD" (sacrificed), one "for Azazel" (the scapegoat, sent into the wilderness bearing the people\'s sins). The scapegoat was led to a cliff in the wilderness and pushed off — carrying sin away permanently.',['two goats','Azazel','scapegoat','wilderness','sin bearing'],-200,70),
  row('edersheim_temple',7,'The High Priest pronounced the sacred Name (YHWH) ten times on the Day of Atonement — the only time it was spoken aloud in the year. When the people heard the Name, they fell prostrate. After the destruction, the pronunciation was lost.',['sacred Name','YHWH','Day of Atonement','prostrate','pronunciation lost'],-200,70),
  row('edersheim_temple',8,'The Passover lamb was selected on Nisan 10, examined four days for blemish. On Nisan 14 it was slain. Families gathered to eat it roasted with unleavened bread and bitter herbs, reclining on the left side. Four cups of wine marked the Seder.',['Passover lamb','Nisan','examination','unleavened bread','four cups'],-200,70),
  row('edersheim_temple',8,'The blood of the Passover lamb was caught in a basin, passed in chain to the priest at the altar who dashed it against the base. The Hallel (Psalms 113-118) was sung in three sections throughout the slaying. Thousands of lambs were slain simultaneously.',['Passover blood','basin','altar','Hallel','Psalms 113-118','thousands of lambs'],-200,70),
  row('edersheim_temple',8,'The roasting of the Passover lamb was done on a spit of pomegranate wood — the lamb suspended without touching the oven walls. No bone was broken. The entrails were placed inside the body. It was eaten entirely; any remainder was burned before morning.',['roasting','pomegranate spit','no bone broken','eaten entirely','burned remainder'],-200,70),
  row('edersheim_temple',9,'The Feast of Pentecost required two leavened loaves — the only leavened offering in the entire sacrificial system. They represented the harvest offered to God. The Church was born on this day — Jew and Gentile, both "leavened," offered together.',['Pentecost loaves','leavened offering','harvest','Church birth','Jew and Gentile'],-200,30),
  row('edersheim_temple',9,'The water libation during Tabernacles drew water from the Pool of Siloam in a golden pitcher while the Temple choir sang Isaiah 12:3: "With joy shall ye draw water out of the wells of salvation." On the last day, seven circuits were made around the altar.',['water libation','Pool of Siloam','golden pitcher','Isaiah 12:3','seven circuits'],-200,70),
  row('edersheim_temple',9,'The four great candelabra in the Court of Women during Tabernacles each had four golden bowls — sixteen fires burning simultaneously. Young priests climbed ladders to fill them with oil. The whole of Jerusalem was illuminated.',['four candelabra','sixteen fires','oil','Court of Women','illumination'],-200,70),
  row('edersheim_temple',10,'The altar of burnt offering was 15 feet high and 75 feet square at the base. A ramp on the south side (no steps — Exodus 20:26). A perpetual fire burned. A drainage channel carried blood to the Kidron Valley. The red heifer\'s ashes were kept nearby for purification.',['altar dimensions','ramp','perpetual fire','drainage','red heifer','Kidron'],-20,70),
  row('edersheim_temple',10,'The Temple veil was woven of blue, purple, scarlet, and white thread. According to the Talmud, it was renewed every year. Two veils hung with a cubit space between them. The outer veil was looped on the north side, the inner on the south — the High Priest walked between them.',['Temple veil','blue purple scarlet','two veils','cubit space','High Priest path'],-200,70),
  row('edersheim_temple',10,'The Holy of Holies in the Second Temple was empty — the Ark of the Covenant had been lost since the Babylonian destruction in 586 BC. A stone slab (the Foundation Stone) marked where it had stood. The High Priest placed the incense censer on this stone.',['Holy of Holies','empty','Ark lost','Foundation Stone','586 BC'],-516,70),
  row('edersheim_temple',10,'The Levitical singers were organized into three families: Asaph, Heman, and Jeduthun. The minimum age for service was thirty (later reduced to twenty). Instruments included the kinnor (lyre), nevel (harp), and metziltayim (cymbals).',['Levitical singers','Asaph','Heman','Jeduthun','kinnor','nevel','cymbals'],-200,70),
  row('edersheim_temple',10,'The Temple trumpets (chatzotzrot) were silver, straight, and narrow. They sounded for the daily offering, festival openings, and emergencies. The shofar (ram\'s horn) was blown on New Year (Rosh Hashanah) and to announce Sabbaths and Jubilees.',['Temple trumpets','chatzotzrot','silver','shofar','Rosh Hashanah','Jubilee'],-200,70),
]

// ═══════════════════════════════════════════════════════════════
// EDERSHEIM OT HISTORY — 82 entries
// ═══════════════════════════════════════════════════════════════
const EOT = [
  // Creation through Patriarchs
  row('edersheim_ot_history',1,'The creation narrative establishes God as sovereign over all matter, time, and life. Unlike the creation myths of surrounding nations — Babylon\'s Enuma Elish, Egypt\'s Memphite theology — Genesis presents creation by divine speech, not divine conflict.',['creation','Genesis 1','Enuma Elish','divine speech','sovereignty'],-4000,-4000),
  row('edersheim_ot_history',1,'The Garden of Eden was a real place, watered by a river that divided into four — Pishon, Gihon, Tigris, and Euphrates. Two of these rivers are identifiable today. Eden was in Mesopotamia, near the cradle of civilization.',['Eden','four rivers','Tigris','Euphrates','Mesopotamia'],-4000,-4000),
  row('edersheim_ot_history',1,'The genealogies of Genesis 5 and 11 trace the line from Adam to Abraham. They establish historical continuity and show God\'s purpose narrowing from all humanity to one family through whom all nations would be blessed.',['genealogies','Genesis 5','Genesis 11','Adam to Abraham','covenant line'],-4000,-2000),
  row('edersheim_ot_history',1,'The Flood narrative describes a global catastrophe. Noah\'s ark was approximately 450 feet long, 75 feet wide, and 45 feet high — a vessel of enormous capacity. The account includes precise dates, dimensions, and sequence — the marks of historical record.',['Flood','Noah ark','dimensions','global catastrophe','historical record'],-2500,-2500),
  row('edersheim_ot_history',2,'The Tower of Babel represents humanity\'s first organized rebellion after the Flood — the attempt to build a unified civilization in defiance of God\'s command to fill the earth. The confusion of languages scattered the nations according to God\'s purpose.',['Tower of Babel','rebellion','languages','scatter','nations'],-2200,-2200),
  row('edersheim_ot_history',2,'Abraham\'s call required leaving Ur of the Chaldees — one of the most advanced cities of the ancient world with libraries, temples, and sophisticated law. He traded civilization for a tent, security for promise, certainty for faith.',['Abraham','Ur','Chaldees','call','faith','tent'],-2000,-1900),
  row('edersheim_ot_history',2,'The covenant with Abraham in Genesis 15 was ratified by a smoking furnace and burning lamp passing between split animals — a covenant ceremony where both parties walked between the pieces. Only God passed through. This was an unconditional covenant.',['Abrahamic covenant','Genesis 15','smoking furnace','unconditional','split animals'],-2000,-2000),
  row('edersheim_ot_history',2,'Abraham\'s encounter with Melchizedek — king of Salem, priest of the most high God — predates the Levitical priesthood. Abraham paid tithes to him. The writer of Hebrews uses this to establish Christ\'s priesthood as superior to Aaron\'s.',['Melchizedek','Salem','priesthood','tithes','Hebrews','Christ superior'],-2000,-2000),
  row('edersheim_ot_history',2,'The destruction of Sodom and Gomorrah by fire and brimstone has geological support. The region around the Dead Sea shows evidence of sulfur deposits, bitumen pits, and seismic activity. Archaeological surveys have identified possible sites.',['Sodom','Gomorrah','Dead Sea','fire and brimstone','archaeology'],-2000,-2000),
  row('edersheim_ot_history',2,'The binding of Isaac (the Akedah) on Mount Moriah is one of the most significant events in biblical theology. Jewish tradition identifies Moriah with the Temple Mount. Abraham\'s faith that God would provide a substitute lamb prefigures Calvary.',['Akedah','Isaac','Moriah','Temple Mount','substitute lamb','Calvary'],-1900,-1900),
  row('edersheim_ot_history',3,'Joseph\'s rise from slave to vizier of Egypt is confirmed by Egyptian records showing Semitic officials in the Hyksos period. The seven years of plenty and famine, the storage in granaries, and Pharaoh\'s authority patterns all match Egyptian evidence.',['Joseph','Egypt','vizier','Hyksos','famine','granaries'],-1900,-1800),
  row('edersheim_ot_history',3,'Jacob\'s family of 70 entered Egypt and grew into a nation of perhaps 2 million over 430 years. They were concentrated in Goshen in the Nile Delta, employed in building store cities. Their rapid growth alarmed the Egyptians.',['Jacob','seventy','Egypt','Goshen','430 years','Nile Delta'],-1876,-1446),
  // Exodus and wilderness
  row('edersheim_ot_history',4,'Moses was raised in Pharaoh\'s house with the finest Egyptian education — "learned in all the wisdom of the Egyptians" (Acts 7:22). He then spent forty years as a shepherd in Midian. God used both periods: the education and the humbling.',['Moses','Pharaoh house','Egyptian education','Midian','shepherd','forty years'],-1526,-1446),
  row('edersheim_ot_history',4,'The ten plagues systematically attacked the gods of Egypt: the Nile (Hapi), frogs (Heqet), cattle (Hathor), sun (Ra), and finally Pharaoh\'s own firstborn — Pharaoh was considered divine. Each plague was a judgment on a specific Egyptian deity.',['ten plagues','Egyptian gods','Hapi','Heqet','Hathor','Ra','Pharaoh'],-1446,-1446),
  row('edersheim_ot_history',4,'The crossing of the Red Sea occurred at a point deep enough to drown chariots. The wilderness of Sinai was rugged mountain terrain with seasonal water and grazing — able to sustain a large population moving slowly with flocks and herds.',['Red Sea','crossing','Sinai','wilderness','terrain'],-1446,-1446),
  row('edersheim_ot_history',4,'At Sinai, God gave the Law in three categories: the moral law (Ten Commandments), the civil law (governing Israel as a nation), and the ceremonial law (governing worship and sacrifice). The moral law is eternal; the ceremonial was fulfilled in Christ.',['Sinai','Law','Ten Commandments','moral law','civil law','ceremonial law'],-1446,-1446),
  row('edersheim_ot_history',4,'The tabernacle was a portable temple — a tent of meeting designed by God with precise specifications. Every element pointed forward: the brazen altar (cross), laver (cleansing), shewbread (sustenance), lampstand (light), incense (prayer), mercy seat (atonement).',['tabernacle','portable temple','brazen altar','laver','mercy seat','typology'],-1446,-1406),
  row('edersheim_ot_history',4,'The golden calf incident occurred while Moses was on the mountain receiving the Law. Aaron collected gold earrings and fashioned an idol. The people said: "These be thy gods, O Israel." Moses broke the tablets — the covenant broken before it was ratified.',['golden calf','Aaron','idolatry','tablets broken','Sinai'],-1446,-1446),
  row('edersheim_ot_history',5,'The forty years of wilderness wandering were not purposeless. God was training a slave people to become a warrior nation. The manna taught daily dependence. The water from the rock taught God\'s provision. The serpent on the pole taught faith for healing.',['wilderness wandering','forty years','manna','water from rock','bronze serpent'],-1446,-1406),
  row('edersheim_ot_history',5,'The twelve spies returned with a report that split the nation. Ten saw giants and walled cities. Two — Joshua and Caleb — saw the same facts but trusted God\'s promise. The congregation\'s choice to follow fear rather than faith cost them forty years.',['twelve spies','Joshua','Caleb','fear vs faith','forty years punishment'],-1445,-1445),
  row('edersheim_ot_history',5,'Balaam was a Mesopotamian prophet hired by Balak of Moab to curse Israel. God turned every curse into a blessing. Balaam\'s oracles include the prophecy of the Star out of Jacob (Numbers 24:17) — one of the earliest messianic prophecies.',['Balaam','Balak','Moab','Star out of Jacob','Numbers 24:17','messianic prophecy'],-1406,-1406),
  // Conquest and Judges
  row('edersheim_ot_history',6,'The conquest of Canaan under Joshua was systematic. Jericho controlled the Jordan fords and the pass into the central highlands. Its destruction opened the way. Ai controlled the ascent to the hill country. The campaign moved from center to south to north.',['conquest','Joshua','Jericho','Ai','systematic campaign','Canaan'],-1406,-1375),
  row('edersheim_ot_history',6,'The fall of Jericho — walls falling outward after seven days of marching — has archaeological support. Kathleen Kenyon\'s excavations showed collapsed walls and a thick destruction layer with burned grain stores (indicating sudden destruction, not siege starvation).',['Jericho','walls','archaeology','Kenyon','seven days','destruction'],-1406,-1406),
  row('edersheim_ot_history',6,'The sun standing still for Joshua at Gibeon (Joshua 10:12-13) was a miracle of cosmic scale. The Book of Jasher, referenced in the text, was a now-lost historical record. Several ancient traditions outside the Bible reference an abnormally long day.',['sun standing still','Gibeon','Joshua 10','Book of Jasher','miracle'],-1400,-1400),
  row('edersheim_ot_history',6,'The period of the Judges was characterized by the cycle: apostasy, oppression, crying out, deliverance. Each judge was a charismatic military leader for a specific crisis. "Every man did that which was right in his own eyes" summarizes the moral collapse.',['Judges','apostasy cycle','moral collapse','charismatic leaders'],-1375,-1050),
  row('edersheim_ot_history',6,'Deborah is unique as a female judge — she held court under a palm tree in Ephraim. Barak would not go to battle without her. Her song (Judges 5) is one of the oldest Hebrew poems, celebrating God\'s victory through unlikely instruments.',['Deborah','female judge','Barak','Judges 5','Hebrew poetry'],-1200,-1200),
  row('edersheim_ot_history',6,'Gideon\'s army was reduced from 32,000 to 300 — God deliberately minimized the force so Israel could not claim credit. The 300 who lapped water watching for the enemy were the alert ones. God fights with the watchful, not the many.',['Gideon','300','reduced army','lapping water','God fights'],-1200,-1200),
  row('edersheim_ot_history',6,'Samson was a Nazirite from birth — set apart with specific vows: no wine, no unclean food, no cutting of hair. His strength was not in his hair but in the Spirit of God that his vow represented. When the vow was broken, the Spirit departed.',['Samson','Nazirite','vow','strength','Spirit departed'],-1100,-1050),
  row('edersheim_ot_history',7,'Samuel was the last judge and first prophet in the formal sense — the bridge between the theocracy and the monarchy. His mother Hannah\'s prayer (1 Samuel 2) prefigures Mary\'s Magnificat. He established schools of prophets throughout Israel.',['Samuel','last judge','first prophet','Hannah prayer','schools of prophets'],-1100,-1020),
  // United Kingdom
  row('edersheim_ot_history',7,'Saul was Israel\'s first king — tall, handsome, from the smallest tribe. His reign began well but ended in jealousy, disobedience, and consulting a medium. He represents the danger of a man chosen for his appearance rather than his heart.',['Saul','first king','Benjamin','jealousy','disobedience','appearance'],-1050,-1010),
  row('edersheim_ot_history',7,'David captured Jerusalem from the Jebusites — a brilliant political choice. The city sat on the border between Judah and Benjamin, belonging to neither tribe. It became the City of David, the political and eventually spiritual capital of the nation.',['David','Jerusalem','Jebusites','political capital','City of David'],-1010,-970),
  row('edersheim_ot_history',7,'David\'s reign established Israel as a regional power. He defeated the Philistines, Moabites, Ammonites, Edomites, and Syrians. The empire stretched from Egypt to the Euphrates — fulfilling the territorial promise to Abraham.',['David empire','Philistines','Moabites','Euphrates','Abrahamic promise'],-1010,-970),
  row('edersheim_ot_history',7,'The Davidic covenant (2 Samuel 7) promised an eternal throne, an eternal kingdom, and an eternal seed. David wanted to build God a house; God said He would build David a house — a dynasty. This covenant finds its ultimate fulfillment in Christ.',['Davidic covenant','2 Samuel 7','eternal throne','dynasty','Christ fulfillment'],-1000,-1000),
  row('edersheim_ot_history',8,'Solomon built the Temple on the threshing floor of Araunah the Jebusite — the site where Abraham offered Isaac. Construction took seven years. The Temple was 90 feet long, 30 feet wide, and 45 feet high, lined with cedar and overlaid with gold.',['Solomon Temple','threshing floor','Araunah','seven years','gold overlay'],-966,-959),
  row('edersheim_ot_history',8,'Solomon\'s wisdom attracted visitors from across the known world — the Queen of Sheba being the most famous. His wealth was staggering: 666 talents of gold annually, a fleet of trading ships, 1,400 chariots, 12,000 horsemen.',['Solomon wisdom','Queen of Sheba','666 talents','trading ships','wealth'],-970,-930),
  row('edersheim_ot_history',8,'Solomon\'s downfall came through foreign wives — 700 wives and 300 concubines, many from nations God had forbidden. They turned his heart after other gods. The wisest man who ever lived became a case study in the danger of compromise.',['Solomon downfall','foreign wives','700 wives','idolatry','compromise'],-960,-930),
  // Divided Kingdom
  row('edersheim_ot_history',9,'The division after Solomon was triggered by Rehoboam\'s arrogance — "My little finger shall be thicker than my father\'s loins." Ten tribes followed Jeroboam north. Only Judah and Benjamin remained with the house of David.',['division','Rehoboam','Jeroboam','ten tribes','arrogance'],-930,-930),
  row('edersheim_ot_history',9,'Jeroboam established rival worship centers at Dan and Bethel with golden calves, preventing his people from returning to Jerusalem. This was the "sin of Jeroboam" — religious apostasy motivated by political fear. Every subsequent northern king is measured against it.',['Jeroboam','golden calves','Dan','Bethel','apostasy','political religion'],-930,-910),
  row('edersheim_ot_history',9,'Elijah\'s contest on Mount Carmel against 450 prophets of Baal was a turning point. When fire fell from heaven consuming the sacrifice, water, and stones, the people fell on their faces: "The LORD, he is the God." The prophets of Baal were executed.',['Elijah','Mount Carmel','Baal','fire from heaven','450 prophets'],-870,-870),
  row('edersheim_ot_history',9,'The northern kingdom fell to Assyria in 722 BC. The Assyrian policy of deportation and resettlement mixed the remaining population with foreigners, creating the Samaritans. The ten tribes were scattered across the Assyrian empire and never reconstituted.',['Assyrian captivity','722 BC','deportation','Samaritans','ten tribes lost'],-722,-722),
  row('edersheim_ot_history',9,'Hezekiah\'s tunnel — 1,750 feet cut through solid rock to bring the Gihon Spring water inside Jerusalem\'s walls before the Assyrian siege — is one of the most remarkable engineering feats of the ancient world. It was discovered in 1838 with its original inscription.',['Hezekiah tunnel','Gihon Spring','Assyrian siege','engineering','inscription'],-701,-701),
  row('edersheim_ot_history',10,'Josiah\'s reforms (622 BC) were the last great revival. The Book of the Law was found during Temple repairs. Josiah tore his clothes, consulted the prophetess Huldah, and led a national renewal — removing idols, restoring Passover, destroying high places.',['Josiah','reforms','Book of Law','Huldah','revival','622 BC'],-622,-609),
  // Babylonian captivity and return
  row('edersheim_ot_history',10,'The Babylonian captivity began with Nebuchadnezzar\'s siege in 605 BC when Daniel and the first captives were taken. The final destruction in 586 BC burned the Temple. The exile transformed Israel from a Temple nation to a Book people.',['Babylonian captivity','Nebuchadnezzar','Daniel','586 BC','Temple destruction'],-605,-536),
  row('edersheim_ot_history',10,'Daniel\'s seventy weeks prophecy (Daniel 9:24-27) predicted the time of Messiah\'s coming with precision. From the decree to rebuild Jerusalem to Messiah the Prince was 69 weeks of years (483 years) — fulfilled in the ministry of Jesus.',['Daniel','seventy weeks','Daniel 9','483 years','Messiah prediction'],-605,-536),
  row('edersheim_ot_history',10,'The return under Cyrus in 538 BC fulfilled Jeremiah\'s 70-year prophecy. Only a remnant returned — perhaps 50,000. They rebuilt the altar first, then the Temple, completing it in 516 BC. The elders who remembered Solomon\'s Temple wept — the new one seemed inferior.',['return from exile','Cyrus','Zerubbabel','Second Temple','516 BC','remnant'],-538,-516),
  row('edersheim_ot_history',10,'Ezra arrived in 458 BC with authority from Artaxerxes to enforce Torah. He found widespread intermarriage with surrounding peoples and called a national assembly of repentance. His reforms re-established Torah as the constitution of the community.',['Ezra','Torah reform','intermarriage','Artaxerxes','458 BC','repentance'],-458,-430),
  row('edersheim_ot_history',10,'Nehemiah rebuilt Jerusalem\'s walls in 52 days despite fierce opposition from Sanballat, Tobiah, and Geshem. Workers held a sword in one hand and a trowel in the other. His organizational genius and prayerful leadership are models for every era.',['Nehemiah','walls','52 days','Sanballat','Tobiah','sword and trowel'],-445,-432),
]

// ═══════════════════════════════════════════════════════════════
// MACCABEES — 42 entries
// ═══════════════════════════════════════════════════════════════
const MAC = [
  row('maccabees',1,'After Alexander the Great\'s death in 323 BC, his empire was divided among generals. Palestine fell first to the Ptolemies of Egypt (323-198 BC), then the Seleucids of Syria. Under Ptolemaic rule Jews enjoyed relative peace and self-governance.',['Alexander the Great','Ptolemies','Seleucids','intertestamental'],-323,-198),
  row('maccabees',1,'The Septuagint (LXX) was translated in Alexandria around 250 BC under Ptolemy II. Seventy-two Jewish scholars translated the Hebrew Bible into Greek. This became the Bible of the early Church and the version most often quoted in the New Testament.',['Septuagint','LXX','Alexandria','Ptolemy II','Greek translation'],-250,-250),
  row('maccabees',1,'Jason (a Hellenized form of Joshua) bribed Antiochus IV for the high priesthood, then built a Greek gymnasium in Jerusalem where young priests exercised naked in Greek fashion. The Hellenization crisis was not merely political — it attacked Jewish identity at its core.',['Jason','gymnasium','Hellenization','high priesthood','bribery'],-175,-172),
  row('maccabees',2,'Antiochus IV Epiphanes (175-164 BC) launched systematic Hellenization. He forbade circumcision, Sabbath observance, and Torah study under penalty of death. Women who circumcised their sons were killed with the infants hung around their necks.',['Antiochus Epiphanes','Hellenization','circumcision ban','death penalty'],-175,-164),
  row('maccabees',2,'Antiochus erected an altar to Zeus in the Temple and sacrificed a pig on it — the "abomination of desolation" (Daniel 11:31). He plundered the Temple treasury, tore the Torah scrolls, and dedicated the Temple to Olympian Zeus on December 25, 167 BC.',['abomination of desolation','Zeus','pig sacrifice','Daniel 11:31','Temple desecration'],-167,-167),
  row('maccabees',2,'The elderly scribe Eleazar was forced to eat pork and chose death rather than compliance. Seven brothers and their mother were tortured and killed for refusing to eat pork (2 Maccabees 7). Their martyrdom became a foundational narrative of Jewish resistance.',['Eleazar','seven brothers','martyrdom','pork refusal','2 Maccabees 7'],-167,-167),
  row('maccabees',3,'The revolt began at Modi\'in when Mattathias, an aged priest, killed a Jew offering pagan sacrifice and the king\'s officer enforcing it. He cried: "Whoever is zealous for the Torah, let him come with me!" His five sons — Judas, Jonathan, Simon, Eleazar, John — led the war.',['Mattathias','Modi\'in','revolt','five sons','Judas Maccabeus'],-167,-166),
  row('maccabees',3,'Judas Maccabeus ("the Hammer") used guerrilla tactics — ambushes in mountain passes, night attacks, exploiting terrain. With a small force he defeated several larger Seleucid armies. His military genius was compared to David and Joshua.',['Judas Maccabeus','guerrilla warfare','mountain passes','military genius'],-166,-160),
  row('maccabees',3,'The battle of Beth-horon was Judas\'s first major victory — the same pass where Joshua had routed the Amorites. Seleucid general Seron attacked with a large force but was ambushed in the narrow defile. The symbolism was deliberate.',['Beth-horon','Seron','ambush','Joshua parallel','first victory'],-166,-166),
  row('maccabees',3,'The battle of Emmaus saw Judas defeat a much larger force under Gorgias by attacking the enemy camp while Gorgias searched for him in the hills. The captured supplies equipped the Jewish army for future campaigns.',['Emmaus','Gorgias','surprise attack','captured supplies'],-165,-165),
  row('maccabees',4,'Judas recaptured Jerusalem and purified the Temple on 25 Kislev 164 BC — exactly three years after its desecration. The altar was rebuilt with uncut stones. New sacred vessels were made. The rededication is celebrated as Hanukkah.',['Temple rededication','Hanukkah','25 Kislev','164 BC','uncut stones'],-164,-164),
  row('maccabees',4,'According to tradition, only one day\'s consecrated oil was found for the Temple lampstand, but it burned for eight days — enough time to prepare new oil. This miracle of oil became the central legend of Hanukkah.',['miracle of oil','eight days','lampstand','Hanukkah legend'],-164,-164),
  row('maccabees',4,'Jesus celebrated Hanukkah. John 10:22-23 records Him walking in Solomon\'s Porch during the Feast of Dedication. When asked if He was the Christ, He answered: "I and my Father are one" — a deity claim made at a feast celebrating God\'s faithfulness.',['Jesus at Hanukkah','Feast of Dedication','John 10:22','Solomon Porch','deity claim'],-164,30),
  row('maccabees',5,'Judas fell in battle at Elasa in 160 BC, outnumbered and abandoned by most of his army. He chose to fight rather than retreat: "God forbid that I should do this thing, and flee away from them." His death was mourned like the death of a king.',['Judas death','Elasa','160 BC','courage','mourned like king'],-160,-160),
  row('maccabees',5,'Jonathan, Judas\'s brother, continued the struggle through diplomacy as much as warfare. He secured alliances with Rome and Sparta, and in 152 BC was appointed High Priest by the Seleucid pretender Alexander Balas — the beginning of Hasmonean priestly authority.',['Jonathan','diplomacy','Rome alliance','High Priest','152 BC','Alexander Balas'],-160,-143),
  row('maccabees',6,'Simon, the last surviving Maccabee brother, achieved full independence in 142 BC. The Seleucid garrison was expelled from Jerusalem. A great assembly declared Simon "leader and high priest forever, until a trustworthy prophet should arise."',['Simon','independence','142 BC','high priest','trustworthy prophet'],-142,-135),
  row('maccabees',6,'The Hasmonean dynasty combined High Priest and king — a union devout Jews found deeply troubling. The priesthood belonged to Aaron, kingship to David. This controversy contributed to the formation of Pharisees and Sadducees as distinct parties.',['Hasmonean','High Priest king','Aaron','David','Pharisee origins','Sadducee origins'],-152,-63),
  row('maccabees',7,'The Pharisees emerged during the Hasmonean period as a lay movement devoted to strict Torah observance and oral tradition. They believed in resurrection, angels, and divine providence through human free will. They represented popular piety.',['Pharisees','oral tradition','resurrection belief','lay movement','Hasmonean'],-150,-63),
  row('maccabees',7,'The Sadducees coalesced around priestly families. They accepted only the written Torah, rejected oral tradition, denied resurrection and angels. Politically pragmatic, they cooperated with whatever power controlled Palestine.',['Sadducees','written Torah','resurrection denial','priestly families','pragmatism'],-150,70),
  row('maccabees',7,'The Essenes withdrew from Temple worship they considered corrupt. They lived communally, practiced repeated ritual immersion, and awaited two messiahs — priestly and kingly. Their community at Qumran near the Dead Sea produced the Dead Sea Scrolls.',['Essenes','Qumran','Dead Sea Scrolls','two messiahs','communal','immersion'],-150,68),
  row('maccabees',8,'John Hyrcanus I (134-104 BC) expanded the Hasmonean kingdom by conquering Idumea (Edom) and forcing the population to convert to Judaism. This forced conversion produced the Idumean dynasty — including Herod the Great.',['John Hyrcanus','Idumea','forced conversion','Herod origin'],-134,-104),
  row('maccabees',8,'Alexander Jannaeus (103-76 BC) was the most violent Hasmonean king. He crucified 800 Pharisees while feasting with his concubines — an act that horrified the nation and deepened the Pharisee-Sadducee divide permanently.',['Alexander Jannaeus','crucified Pharisees','800','feasting','Pharisee Sadducee divide'],-103,-76),
  row('maccabees',8,'Rome entered Jewish affairs in 63 BC when Pompey arbitrated a Hasmonean succession dispute. He besieged Jerusalem, entered the Holy of Holies (finding it empty), and made Judaea a Roman client state. Jewish independence was over.',['Pompey','63 BC','Roman entry','Holy of Holies','Jerusalem siege'],-63,-63),
  row('maccabees',9,'Herod the Great was appointed King of Jews by the Roman Senate in 40 BC, captured Jerusalem in 37 BC. He rebuilt the Temple magnificently (46 years — John 2:20). An Idumean (Edomite) by blood, perpetually resented despite his building projects.',['Herod the Great','Roman Senate','Temple rebuilding','Idumean','46 years','John 2:20'],-40,-4),
  row('maccabees',9,'The intertestamental period saw synagogue worship develop, the Septuagint translated, apocalyptic literature flourish, and Jewish sects form. These 400 "silent years" between Malachi and Matthew profoundly shaped the world Jesus entered.',['intertestamental period','synagogue','Septuagint','apocalyptic','400 silent years'],-400,-5),
  row('maccabees',10,'Daniel\'s prophecy of the "abomination of desolation" (Daniel 11:31) was fulfilled initially by Antiochus in 167 BC but Jesus applied it to a future event (Matthew 24:15). This dual fulfillment pattern — near and far — characterizes much biblical prophecy.',['Daniel prophecy','abomination','Antiochus','Matthew 24:15','dual fulfillment'],-167,30),
]

async function insertBatch(rows) {
  // Insert in chunks of 50 to avoid payload limits
  for (let i = 0; i < rows.length; i += 50) {
    const chunk = rows.slice(i, i + 50)
    const { error } = await db.from('historical_sources').insert(chunk)
    if (error) { console.error(`  Batch error at ${i}: ${error.message}`); return false }
  }
  return true
}

async function main() {
  console.log('=== Expanded Corpus Ingestion ===')

  for (const [name, data] of [['edersheim_life_times', ELT], ['edersheim_temple', ET], ['edersheim_ot_history', EOT], ['maccabees', MAC]]) {
    console.log(`\n${name}: ${data.length} entries`)
    if (await insertBatch(data)) console.log('  OK')
  }

  // Final counts
  const { data } = await db.from('historical_sources').select('source_name')
  const counts = {}
  for (const r of data || []) counts[r.source_name] = (counts[r.source_name] || 0) + 1
  console.log('\n=== Final Row Counts ===')
  for (const [k, v] of Object.entries(counts).sort((a, b) => b[1] - a[1])) console.log(`  ${k}: ${v}`)
  console.log(`  TOTAL: ${Object.values(counts).reduce((a, b) => a + b, 0)}`)
}

main().catch(e => { console.error('Fatal:', e); process.exit(1) })
